static boolean isValidDefineValue(Node val, Set<String> defines) {
  switch (val.getType()) {
    case Token.STRING:
    case Token.NUMBER:
    case Token.TRUE:
    case Token.FALSE:
      return true;

    // Binary operators are only valid if both children are valid.
    case Token.ADD:
    case Token.BITAND:
    case Token.BITOR:
    case Token.BITXOR:
      return isValidDefineValue(val.getFirstChild(), defines)
          && isValidDefineValue(val.getLastChild(), defines);

    // Unary operators are valid if the child is valid.
    case Token.BITNOT:
    case Token.NOT:
    case Token.NEG:
      return isValidDefineValue(val.getFirstChild(), defines);

    // Names are valid if and only if they are defines themselves.
    case Token.NAME:
    case Token.GETPROP:
      if (val.isQualifiedName()) {
        return defines.contains(val.getQualifiedName());
      }
  }
  return false;
}

additional_testcases.testcase:
public void testValidDefineWithBitwiseOperations() {
  assertTrue(testValidDefineValue("1 | 8"));
  assertTrue(testValidDefineValue("1 ^ 8"));
  assertTrue(testValidDefineValue("~5"));
  assertFalse(testValidDefineValue("x | 8"));
  assertFalse(testValidDefineValue("1 | y"));
}

public void testValidDefineWithNestedOperations() {
  assertTrue(testValidDefineValue("(1 + 2) & 8"));
  assertTrue(testValidDefineValue("!(1 + 2)"));
  assertFalse(testValidDefineValue("(x + 2) & 8"));
}
